import{_ as t,W as e,X as l,Z as a}from"./framework-a8aed956.js";const n={},i=a('<h1 id="java-8-function包" tabindex="-1"><a class="header-anchor" href="#java-8-function包" aria-hidden="true">#</a> JAVA 8 FUNCTION包</h1><h1 id="总览" tabindex="-1"><a class="header-anchor" href="#总览" aria-hidden="true">#</a> 总览</h1><table><thead><tr><th style="text-align:left;">接口</th><th style="text-align:left;">解释</th></tr></thead><tbody><tr><td style="text-align:left;">Consumer&lt; T &gt;</td><td style="text-align:left;">接收T对象，无返回值</td></tr><tr><td style="text-align:left;">Function&lt; T, R &gt;</td><td style="text-align:left;">接收T对象，返回R对象</td></tr><tr><td style="text-align:left;">Predicate&lt; T&gt;</td><td style="text-align:left;">接收T对象，返回boolean值</td></tr><tr><td style="text-align:left;">Supplier&lt; T &gt;</td><td style="text-align:left;">提供T对象（例如工厂），不接收值</td></tr><tr><td style="text-align:left;">BiFunction&lt; T, U, R &gt;</td><td style="text-align:left;">接收T对象和U对象，返回R对象</td></tr><tr><td style="text-align:left;">UnaryOperator&lt; T &gt;</td><td style="text-align:left;">接收T对象，返回T对象</td></tr><tr><td style="text-align:left;">BinaryOperator&lt; T &gt;</td><td style="text-align:left;">接收两个T对象，返回T对象，继承于BiFunction</td></tr></tbody></table><p>标注为FunctionalInterface的接口被称为函数式接口，该接口只能有一个自定义方法，但是可以包括从object类继承而来的方法。如果一个接口只有一个方法，则编译器会认为这就是一个函数式接口。是否是一个函数式接口，需要注意的有以下几点：</p><ul><li>该注解只能标记在”有且仅有一个抽象方法”的接口上。</li><li>JDK8接口中的静态方法和默认方法，都不算是抽象方法。</li><li>接口默认继承java.lang.Object，所以如果接口显示声明覆盖了Object中方法，那么也不算抽象方法。</li><li>该注解不是必须的，如果一个接口符合”函数式接口”定义，那么加不加该注解都没有影响。加上该注解能够更好地让编译器进行检查。如果编写的不是函数式接口，但是加上了@FunctionInterface，那么编译器会报错。</li><li>在一个接口中定义两个自定义的方法，就会产生Invalid ‘@FunctionalInterface’ annotation; FunctionalInterfaceTest is not a functional interface错误.</li></ul>',5),r=[i];function d(c,o){return e(),l("div",null,r)}const f=t(n,[["render",d],["__file","JAVA 8 FUNCTION包.html.vue"]]);export{f as default};
